public final class TransactionProcessor {
    private let store: SecureStore
    private let auth: AuthorizationProvider
    private let lock = NSLock()

    public init(store: SecureStore, authorizationProvider: AuthorizationProvider = DefaultAuthorizationProvider()) {
        self.store = store
        self.auth = authorizationProvider
    }

    public func createAccount(name: String, currencyCode: String, openingBalanceMinor: Int64 = 0) throws -> Account {
        guard openingBalanceMinor >= 0 else { throw BankingError.invalidAmount }
        return try lock.withLock {
            var state = try store.loadState()
            var account = Account(name: name, currencyCode: currencyCode, balanceMinor: openingBalanceMinor, updatedAt: Date())
            state.accounts[account.id] = account
            state.accountTransactionIndex[account.id] = []
            state.revision &+= 1
            try store.saveState(state)
            return account
        }
    }

    public func getAccount(_ id: UUID) throws -> Account {
        try lock.withLock {
            let state = try store.loadState()
            guard let account = state.accounts[id] else { throw BankingError.accountNotFound }
            return account
        }
    }

    public func listAccounts() throws -> [Account] {
        try lock.withLock {
            let state = try store.loadState()
            return state.accounts.values.sorted { $0.updatedAt > $1.updatedAt }
        }
    }

    public func listTransactions(accountId: UUID) throws -> [Transaction] {
        try lock.withLock {
            let state = try store.loadState()
            guard state.accounts[accountId] != nil else { throw BankingError.accountNotFound }
            let ids = state.accountTransactionIndex[accountId] ?? []
            return ids.compactMap { state.transactions[$0] }.sorted { $0.timestamp > $1.timestamp }
        }
    }

    public func postTransaction(
        accountId: UUID,
        type: TransactionType,
        amountMinor: Int64,
        currencyCode: String,
        memo: String? = nil,
        timestamp: Date = Date()
    ) throws -> (account: Account, transaction: Transaction) {
        guard auth.isAuthorizedToTransact() else { throw BankingError.unauthorized }
        guard amountMinor > 0 else { throw BankingError.invalidAmount }

        return try lock.withLock {
            var state = try store.loadState()
            guard var account = state.accounts[accountId] else { throw BankingError.accountNotFound }
            guard account.currencyCode.uppercased() == currencyCode.uppercased() else { throw BankingError.currencyMismatch }

            let delta: Int64
            switch type {
            case .credit: delta = amountMinor
            case .debit:
                delta = -amountMinor
                if account.balanceMinor + delta < 0 { throw BankingError.insufficientFunds }
            }

            let tx = Transaction(
                accountId: accountId,
                type: type,
                amountMinor: amountMinor,
                currencyCode: currencyCode.uppercased(),
                timestamp: timestamp,
                memo: memo
            )

            account.balanceMinor &+= delta
            account.updatedAt = Date()

            state.accounts[accountId] = account
            state.transactions[tx.id] = tx
            state.accountTransactionIndex[accountId, default: []].append(tx.id)
            state.revision &+= 1

            try store.saveState(state)
            return (account, tx)
        }
    }

    public func deleteTransaction(_ transactionId: UUID) throws -> Account {
        guard auth.isAuthorizedToTransact() else { throw BankingError.unauthorized }

        return try lock.withLock {
            var state = try store.loadState()
            guard let tx = state.transactions[transactionId] else { throw BankingError.transactionNotFound }
            guard var account = state.accounts[tx.accountId] else { throw BankingError.accountNotFound }

            let delta: Int64
            switch tx.type {
            case .credit: delta = -tx.amountMinor
            case .debit: delta = tx.amountMinor
            }

            if account.balanceMinor + delta < 0 { throw BankingError.insufficientFunds }

            account.balanceMinor &+= delta
            account.updatedAt = Date()

            state.accounts[account.id] = account
            state.transactions.removeValue(forKey: transactionId)
            if var arr = state.accountTransactionIndex[account.id] {
                arr.removeAll { $0 == transactionId }
                state.accountTransactionIndex[account.id] = arr
            }
            state.revision &+= 1

            try store.saveState(state)
            return account
        }
    }
}

// MARK: - Formatting / Display

public struct MoneyFormatter {
    public init() {}

    public func string(amountMinor: Int64, currencyCode: String, locale: Locale = .current) -> String {
        let formatter = NumberFormatter()
        formatter.numberStyle = .currency
        formatter.currencyCode = currencyCode
        formatter.locale = locale

        let fractionDigits = formatter.maximumFractionDigits
        let divisor = pow(10.0, Double(fractionDigits))
        let major = Double(amountMinor) / divisor
        return formatter.string(from: NSNumber(value: major)) ?? "\(major) \(currencyCode)"
    }
}

